import java.util.*;
public class Main {
  public static int countBranchFiles(String[][] commits, String branch) {
    Set<String> files = new HashSet<>();
    for (String[] c : commits)
      if (c[0].equals(branch)) files.add(c[1]);
    return files.size();
  }
  public static void main(String[] args) {
    String[][] commits = {{"feature","auth.py"},{"feature","models.py"},{"main","README.md"},{"feature","auth.py"}};
    System.out.println(countBranchFiles(commits, "feature")); // 2
  }
}

