def mapper(line):
    """Yields (word, 1) for each word in the line."""
    for word in line.lower().split():
        yield (word, 1)

def reducer(pairs):
    """Takes iterable of (word, 1) pairs, returns {word: count} dict."""
    counts = {}
    for word, val in pairs:
        counts[word] = counts.get(word, 0) + val
    return counts

def word_count(lines, top_n=3):
    # Map phase
    mapped = (pair for line in lines for pair in mapper(line))
    # Reduce phase
    counts = reducer(mapped)
    # Sort: count desc, then alphabetically
    sorted_counts = sorted(counts.items(), key=lambda x: (-x[1], x[0]))
    for word, count in sorted_counts[:top_n]:
        print(f'{word} {count}')

lines = ['hello world', 'hello python', 'world of python python']
word_count(lines)

