import re

def match_path(pattern, path):
    """Returns True if path matches the route pattern."""
    pattern_parts = pattern.split('/')
    path_parts = path.split('/')
    if len(pattern_parts) != len(path_parts):
        return False
    for p, r in zip(pattern_parts, path_parts):
        if p.startswith('{') and p.endswith('}'):
            continue  # dynamic segment, always matches
        if p != r:
            return False
    return True

def validate_requests(routes, requests):
    for method, path in requests:
        matched = any(
            rm == method and match_path(rp, path)
            for rm, rp in routes
        )
        print('VALID' if matched else 'INVALID')

routes = [('GET','/users'),('GET','/users/{id}'),('POST','/users')]
requests = [('GET','/users'),('GET','/users/42'),('DELETE','/users')]
validate_requests(routes, requests)

